    var _localRecords = JSON.parse(localStorage.getItem('mii_clicker_local_records') || '[]');
    function saveLocalRecord(score, miiData, miiName, postObj, feelingId) {
        var record = {
            record_id: Date.now(),
            create_time: new Date().toISOString(),
            score: score,
            mii_data: miiData,
            mii_name: miiName || 'Anonymous',
            bsky_post_uri: postObj ? postObj.uri : null,
            feeling_id: feelingId || 0,
            post: postObj || null
        };
        _localRecords.unshift(record);
        _localRecords.sort(function(a, b) { return b.score - a.score; });
        _localRecords = _localRecords.slice(0, 100);
        localStorage.setItem('mii_clicker_local_records', JSON.stringify(_localRecords));
        return record;
    }
    function parseCookies() {
        return document.cookie.split(';').reduce(function(acc, c) {
            var parts = c.trim().split('=');
            if (parts.length >= 2) acc[parts[0]] = decodeURIComponent(parts.slice(1).join('='));
            return acc;
        }, {});
    }
    function getHandle() {
        try {
            return JSON.parse(parseCookies()['bsky_session']).data.handle;
        } catch(e) {
            return 'localplayer.bsky.social';
        }
    }
    var OriginalXHR = window.XMLHttpRequest;
    function MockXHR() {
        this._method = null;
        this._url = null;
        this._isMocked = false;
        this.withCredentials = false;
        this.status = 0;
        this.responseText = '';
        this.onload = null;
        this.onerror = null;
        this._realXHR = new OriginalXHR();
        var self = this;
        this._realXHR.onload = function() {
            self.status = self._realXHR.status;
            self.responseText = self._realXHR.responseText;
            if (self.onload) self.onload();
        };
        this._realXHR.onerror = function() {
            if (self.onerror) self.onerror();
        };
    }
    MockXHR.prototype.open = function(method, url, async) {
        this._method = method;
        this._url = url;
        if (url.startsWith('/records') || url.startsWith('/bsky/')) {
            this._isMocked = true;
        } else {
            this._realXHR.open(method, url, async !== false);
        }
    };
    MockXHR.prototype.setRequestHeader = function(h, v) {
        if (!this._isMocked) this._realXHR.setRequestHeader(h, v);
    };
    MockXHR.prototype.getResponseHeader = function(h) {
        if (!this._isMocked) return this._realXHR.getResponseHeader(h);
        return null;
    };
    MockXHR.prototype.send = function(data) {
        if (!this._isMocked) {
            this._realXHR.send(data);
            return;
        }
        var self = this;
        var url = this._url;
        var method = this._method;
        setTimeout(function() {
            if (method === 'GET' && url.startsWith('/records')) {
                var type = url.includes('record_today')      ? 'record_today'
                         : url.includes('record_followings') ? 'record_followings'
                         : url.includes('record_myself')     ? 'record_myself'
                         : 'record_alltime';
                var response;
                if (type === 'record_myself') {
                    response = { type: type, count: _localRecords.length, records: _localRecords };
                } else if (type === 'record_today') {
                    var today = new Date().toDateString();
                    var todayArchived = _ALLTIME_RECORDS.records.filter(function(r) {
                        return new Date(r.create_time).toDateString() === today;
                    });
                    var combined = _localRecords.concat(todayArchived).sort(function(a, b) { return b.score - a.score; }).slice(0, 100);
                    response = { type: type, count: combined.length, records: combined };
                } else if (type === 'record_followings') {
                    response = { type: type, count: 0, records: [] };
                } else {
                    var combined = _localRecords.concat(_ALLTIME_RECORDS.records).sort(function(a, b) { return b.score - a.score; }).slice(0, 100);
                    response = { type: type, count: combined.length, records: combined };
                }
                self.status = 200;
                self.responseText = JSON.stringify(response);
                if (self.onload) self.onload();
            } else if (method === 'POST' && url === '/records') {
                try {
                    var validate = null;
                    var comment  = null;
                    if (data instanceof FormData) {
                        validate = data.get('validate');
                        comment  = data.get('comment');
                    }
                    if (validate) {
                        var parsed = JSON.parse(decodeURIComponent(escape(atob(validate))));
                        var postObj = null;
                        if (comment) {
                            var commentData = JSON.parse(decodeURIComponent(escape(atob(comment))));
                            var handle = getHandle();
                            var postText = (commentData.message || '').trim();
                            if (commentData.is_spoiler) {
                                postText += '\n#MCSpoiler #MiiClicker';
                            } else {
                                postText += '\n#MiiClicker';
                            }
                            var fakePostId = 'NOTREALPOST' + Date.now();
                            postObj = {
                                uri:    'at://did:local:' + handle + '/app.bsky.feed.post/' + fakePostId,
                                cid:    'bafylocal' + fakePostId,
                                author: {
                                    did:         'did:local:' + handle,
                                    handle:      handle,
                                    displayName: handle.split('.')[0],
                                    avatar:      null,
                                    labels:      [],
                                    createdAt:   new Date().toISOString()
                                },
                                record: {
                                    '$type':    'app.bsky.feed.post',
                                    createdAt:  new Date().toISOString(),
                                    text:       postText,
                                    likeCount:  0,
                                    replyCount: 0
                                },
                                likeCount:  0,
                                replyCount: 0,
                                bookmarkCount: 0,
                                quoteCount: 0,
                                labels:     []
                            };
                        }
                        saveLocalRecord(
                            parsed.record.score,
                            parsed.meta.mii_data,
                            parsed.meta.mii_name,
                            postObj,
                            comment ? (commentData ? commentData.feeling_id || 0 : 0) : 0
                        );
                    }
                } catch(e) {
                    console.warn('Could not parse record data:', e);
                }
                self.status = 200;
                self.responseText = JSON.stringify({ success: true, posted: !!comment });
                if (self.onload) self.onload();
            } else if (method === 'POST' && url === '/bsky/auth') {
                try {
                    var username = '';
                    if (data instanceof FormData) {
                        username = data.get('username') || '';
                    }
                    username = username.replace(/^@/, '').trim();
                    if (!username) username = 'localplayer';
                    if (!username.includes('.')) username = username + '.bsky.social';
                    var session = { data: { handle: username } };
                    document.cookie = 'bsky_session=' + encodeURIComponent(JSON.stringify(session)) + '; path=/; SameSite=Lax;';
                    self.status = 200;
                    self.responseText = JSON.stringify({ success: true });
                } catch(e) {
                    self.status = 500;
                    self.responseText = JSON.stringify({ error: 'INTERNAL', message: String(e) });
                }
                if (self.onload) self.onload();
            // If all else fails...
            } else {
                self.status = 404;
                self.responseText = 'Not found';
                if (self.onload) self.onload();
            }
        }, 200);
    };
    window.XMLHttpRequest = MockXHR;
    console.log('We mocking the Server API with this one lol');
